import { streamText } from 'ai';
import { createStreamableValue } from 'ai/rsc';
import regex from 'sensitive-regex';

const detectLeaksInStream = async (model: any, prompt: string) => {
  const result = await streamText({
    model,
    prompt,
    onChunk: (chunk) => {
      // Scan each streaming chunk for secrets
      const secrets = regex(chunk.delta);
      if (secrets.length > 0) {
        console.error('🚨 SENSITIVE DATA DETECTED:', secrets);
        throw new Error('Sensitive data leakage detected');
      }
    }
  });
  return result;
};

