import { generateText } from 'ai';

const safeGenerateText = async (model: any, prompt: string) => {
  try {
    return await generateText({ model, prompt });
  } catch (error) {
    // Sanitize error before logging
    const safeError = error.message.replace(/api_[a-z0-9]{32}/gi, '[REDACTED]');
