import { tool } from 'ai/rsc';
import { z } from 'zod';

const SafeUserSchema = z.object({
  id: z.string(),
  name: z.string().transform((val) => val.replace(/\w+@\w+\.\w+/g, '[EMAIL_REDACTED]')),
  // Explicitly exclude sensitive fields
}).partial();

const safeUserLookup = tool({
  description: 'Lookup sanitized user data',
  parameters: z.object({ userId: z.string() }),
  execute: async ({ userId }) => {
    const user = await db.user.find(userId);
    return SafeUserSchema.parse(user);
  }
});

import { createStreamableValue } from 'ai/rsc';

const redactSensitiveData = (text: string) => {
  const patterns = [
    /sk-[a-zA-Z0-9]{48}/g,
    /\b[A-Za-z0-9]{20}\b/g,
    /xoxb-[0-9a-f]{32}/g
  ];
  return patterns.reduce((clean, pattern) => 
    clean.replace(pattern, '[REDACTED]'), text
  );
};

export const safeStreamUI = async (model: any, prompt: string) => {
  const ui = createStreamableValue();
  (async () => {
    const result = await streamText({ model, prompt });
    for await (const chunk of result.textStream) {
      ui.update(redactSensitiveData(chunk));
    }
    ui.done();
  })();
  return ui.value;
};

